// Double chiffrement AES-256-GCM pour call_logs
const crypto = require('crypto');
const ALGORITHM = 'aes-256-gcm';
const IV_LENGTH = 16;

function hexToBuffer(hex) { return Buffer.from(hex, 'hex'); }

function encryptLayer(data, keyHex) {
  const key = hexToBuffer(keyHex);
  const iv = crypto.randomBytes(IV_LENGTH);
  const cipher = crypto.createCipheriv(ALGORITHM, key, iv);
  const encrypted = Buffer.concat([cipher.update(data), cipher.final()]);
  return { iv, authTag: cipher.getAuthTag(), ciphertext: encrypted };
}

function doubleEncrypt(plaintext, keyA, keyB) {
  const data = Buffer.from(plaintext, 'utf-8');
  const l1 = encryptLayer(data, keyA);
  const l2 = encryptLayer(l1.ciphertext, keyB);
  return Buffer.concat([l1.iv, l1.authTag, l2.iv, l2.authTag, l2.ciphertext]).toString('base64');
}

function encryptField(value, keyA, keyB) {
  if (value === null || value === undefined) return null;
  const str = typeof value === 'string' ? value : JSON.stringify(value);
  return doubleEncrypt(str, keyA, keyB);
}

function esc(val) {
  if (val === null || val === undefined) return 'NULL';
  return "'" + String(val).replace(/'/g, "''") + "'";
}

const keyA = $env.ENCRYPTION_KEY_A;
if (!keyA) throw new Error('ENCRYPTION_KEY_A manquante');
const keyB = $env.ENCRYPTION_KEY_B;
if (!keyB) throw new Error('ENCRYPTION_KEY_B manquante');

const items = $input.all();
const results = [];

for (const item of items) {
  const row = item.json;
  if (!row || !row.id) continue;
  const encLog = encryptField(row.conversation_log, keyA, keyB);
  const encTranscript = encryptField(row.transcript, keyA, keyB);
  const encNotes = encryptField(row.notes, keyA, keyB);
  const encName = encryptField(row.caller_name, keyA, keyB);
  const encEmail = encryptField(row.caller_email, keyA, keyB);
  const encAddr = encryptField(row.caller_address, keyA, keyB);
  const query = `UPDATE call_logs SET conversation_log = ${esc(encLog)}, transcript = ${esc(encTranscript)}, notes = ${esc(encNotes)}, caller_name = ${esc(encName)}, caller_email = ${esc(encEmail)}, caller_address = ${esc(encAddr)}, is_encrypted = true, encrypted_at = NOW() WHERE id = ${esc(row.id)}`;
  results.push({ json: { id: row.id, query, source: 'call' } });
}

// Retourne tableau vide si rien a chiffrer → le noeud suivant ne s'execute pas
return results;

